import PropTypes from 'prop-types'

const Navbar = props => {
    return (
        <header>
            <div className="container">
                <nav className="nav">
                    <div className="menu-togglers">
                        <i className="fas fa-hamburger fa-2x"></i>
                        <i className="fas fa-times"></i>
                    </div>
                    <h5>Praise O</h5>
                </nav>
            </div>
        </header>
    )
}

Navbar.propTypes = {

}

export default Navbar
